def binary_search(arr: List[int], lb: int, ub: int, target: int) -> int:
    """
    A Binary Search Example which has O(log n) time complexity.
    """
    if lb <= ub:
        mid: int = ub + lb // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            return binary_search(arr, mid + 1, ub, target)
        else:
            return binary_search(arr, lb, mid - 1, target)
    else:
        return -1

