def _fullname(attr):
    """Fully qualified name of an attribute."""
    fullname = ""
    if hasattr(attr, "__module__"):
        fullname += attr.__module__
    if hasattr(attr, "__name__"):
        if fullname:
            fullname += "."
        fullname += attr.__name__
    if not fullname:
        fullname = str(attr)
    return fullname

